    68	Expr*
    69	Json2Asg::expr(const llvm::json::Object& jobj)
    70	{
    71	  auto kind = jobj.getString("kind");
    72	  ASSERT(kind);
    73	
    74	  Expr* ret;
    75	
    76	  if (kind == "IntegerLiteral")
    77	    ret = integer_literal(jobj);
    78	
    79	  else if (kind == "BinaryOperator")
    80	    ret = binary_expr(jobj);
    81	
    82	  else if (kind == "UnaryOperator")
    83	    ret = unary_expr(jobj);
    84	
    85	  else if (kind == "DeclRefExpr")
    86	    ret = decl_ref_expr(jobj);
    87	
    88	  else if (kind == "ImplicitCastExpr")
    89	    ret = implicit_cast_expr(jobj);
    90	
    91	  else if (kind == "ParenExpr")
    92	    ret = paren_expr(jobj);
    93	
    94	  else if (kind == "InitListExpr")
    95	    ret = init_list_expr(jobj);
    96	
    97	  else if (kind == "ImplicitValueInitExpr")
    98	    ret = implicit_init_expr(jobj);
    99	
   100	  else if (kind == "ArraySubscriptExpr")
   101	    ret = binary_expr(jobj);
   102	
   103	  else if (kind == "CallExpr")
   104	    ret = call_expr(jobj);
   105	
   106	  else
   107	    ABORT();
   108	
   109	  auto cateVal = jobj.get("valueCategory");
   110	  ASSERT(cateVal);
   111	  auto cate = cateVal->getAsString();
   112	  ASSERT(cate);
   113	  if (cate == "lvalue")
   114	    ret->cate = Expr::Cate::kLValue;
   115	  else if (cate == "prvalue")
   116	    ret->cate = Expr::Cate::kRValue;
   117	  else
   118	    ABORT();
   119	
   120	  return ret;
   121	}
