   124	Json2Asg::integer_literal(const llvm::json::Object& jobj)
   125	{
   126	  auto integerLiteral = make<IntegerLiteral>();
   127	
   128	  integerLiteral->type = getty(jobj);
   129	
   130	  auto value = jobj.getString("value");
